import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import styled from 'styled-components';

// Styled Components
const LoginContainer = styled.div`
  min-height: 78vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
`;

const LoginCard = styled.div`
  background: rgba(255, 255, 255, 0.9);
  backdrop-filter: blur(10px);
  border-radius: 24px;
  padding: 2rem;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.25);
  width: 100%;
  max-width: 400px;
  margin: 1rem;
`;

const Title = styled.h1`
  font-size: 2.5rem;
  font-weight: bold;
  color: #374151;
  text-align: center;
  margin-bottom: 0.5rem;
`;

const Subtitle = styled.p`
  color: #6b7280;
  font-size: 1.2rem;
  text-align: center;
  margin-bottom: 2rem;
`;

const TestNotice = styled.div`
  background: #fef3c7;
  color: #92400e;
  padding: 1rem;
  border-radius: 12px;
  margin-bottom: 1.5rem;
  font-size: 0.875rem;
  text-align: center;
  border: 1px solid #fbbf24;
`;

const GoogleButton = styled.button`
  width: 100%;
  background: white;
  color: #374151;
  font-weight: 600;
  padding: 0.75rem 1rem;
  border-radius: 50px;
  border: 1px solid #d1d5db;
  cursor: pointer;
  transition: all 0.2s ease-in-out;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.75rem;
  margin-bottom: 1rem;
  
  &:hover {
    background: #f9fafb;
    transform: scale(1.02);
  }
  
  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    transform: none;
  }
`;

const TestUserGrid = styled.div`
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0.5rem;
  margin-top: 1rem;
`;

const TestUserButton = styled.button`
  background: #f3f4f6;
  color: #374151;
  border: 1px solid #d1d5db;
  padding: 0.75rem;
  border-radius: 12px;
  cursor: pointer;
  font-size: 0.875rem;
  transition: all 0.2s ease;
  
  &:hover {
    background: #e5e7eb;
    transform: translateY(-1px);
  }
  
  &:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    transform: none;
  }
`;

const ErrorMessage = styled.div`
  background: #fee2e2;
  color: #dc2626;
  padding: 0.75rem;
  border-radius: 8px;
  margin-bottom: 1rem;
  font-size: 0.875rem;
  text-align: center;
`;

const SuccessMessage = styled.div`
  background: #d1fae5;
  color: #065f46;
  padding: 0.75rem;
  border-radius: 8px;
  margin-bottom: 1rem;
  font-size: 0.875rem;
  text-align: center;
`;

const LoadingOverlay = styled.div`
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
`;

const LoadingCard = styled.div`
  background: white;
  padding: 2rem;
  border-radius: 16px;
  text-align: center;
  box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.25);
`;

const LoadingSpinner = styled.div`
  width: 40px;
  height: 40px;
  border: 4px solid #f3f4f6;
  border-top: 4px solid #3b82f6;
  border-radius: 50%;
  animation: spin 1s linear infinite;
  margin: 0 auto 1rem;
  
  @keyframes spin {
    0% { transform: rotate(0deg); }
    100% { transform: rotate(360deg); }
  }
`;

// 테스트용 사용자 데이터
const TEST_USERS = [
  {
    id: '1',
    name: '김철수',
    email: 'kimcs@test.com',
    picture: 'https://i.pravatar.cc/150?img=1',
    createdAt: '2024-01-15T09:00:00Z'
  },
  {
    id: '2',
    name: '이영희',
    email: 'leeyh@test.com',
    picture: 'https://i.pravatar.cc/150?img=2',
    createdAt: '2024-02-20T14:30:00Z'
  },
  {
    id: '3',
    name: '박민수',
    email: 'parkms@test.com',
    picture: 'https://i.pravatar.cc/150?img=3',
    createdAt: '2024-03-10T11:15:00Z'
  },
  {
    id: '4',
    name: '최수진',
    email: 'choisj@test.com',
    picture: 'https://i.pravatar.cc/150?img=4',
    createdAt: '2024-03-25T16:45:00Z'
  }
];

const LoginPageTest = () => {
  const navigate = useNavigate();
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loadingMessage, setLoadingMessage] = useState('');

  // 가짜 Google 로그인 시뮬레이션
  const handleGoogleLogin = () => {
    setIsLoading(true);
    setError('');
    setSuccess('');
    setLoadingMessage('Google 로그인 창을 여는 중...');
    
    // 2초 후 랜덤 사용자로 로그인 처리
    setTimeout(() => {
      const randomUser = TEST_USERS[Math.floor(Math.random() * TEST_USERS.length)];
      handleLoginSuccess(randomUser);
    }, 2000);
  };

  // 특정 테스트 사용자로 로그인
  const handleTestUserLogin = (user) => {
    setIsLoading(true);
    setError('');
    setSuccess('');
    setLoadingMessage(`${user.name}님으로 로그인 중...`);
    
    setTimeout(() => {
      handleLoginSuccess(user);
    }, 1500);
  };

  // 로그인 성공 처리
  const handleLoginSuccess = (user) => {
    // 가짜 토큰 생성
    const fakeAccessToken = `fake_access_token_${user.id}_${Date.now()}`;
    const fakeRefreshToken = `fake_refresh_token_${user.id}_${Date.now()}`;
    
    // 로컬 스토리지에 저장
    localStorage.setItem('accessToken', fakeAccessToken);
    localStorage.setItem('refreshToken', fakeRefreshToken);
    localStorage.setItem('user', JSON.stringify(user));
    
    setLoadingMessage('로그인 완료! 대시보드로 이동 중...');
    setSuccess(`${user.name}님, 로그인 성공!`);
    
    // 1초 후 대시보드로 이동
    setTimeout(() => {
      setIsLoading(false);
      navigate('/dashboard');
    }, 1000);
  };

  // 로그인 실패 시뮬레이션
  const handleLoginError = () => {
    setIsLoading(true);
    setError('');
    setSuccess('');
    setLoadingMessage('로그인 처리 중...');
    
    setTimeout(() => {
      setIsLoading(false);
      setError('로그인에 실패했습니다. 다시 시도해주세요.');
    }, 2000);
  };

  // 페이지 로드 시 기존 로그인 상태 확인
  useEffect(() => {
    const token = localStorage.getItem('accessToken');
    const user = localStorage.getItem('user');
    
    if (token && user) {
      setSuccess('이미 로그인되어 있습니다. 대시보드로 이동합니다.');
      setTimeout(() => {
        navigate('/dashboard');
      }, 1500);
    }
  }, [navigate]);

  return (
    <>
      <LoginContainer>
        <LoginCard>
          {/* 제목 */}
          <Title>LOGIN TEST</Title>
          <Subtitle>테스트용 로그인 페이지</Subtitle>

          {/* 테스트 안내 */}
          <TestNotice>
            🧪 이것은 테스트 버전입니다. 실제 Google 인증 없이 로그인을 시뮬레이션합니다.
          </TestNotice>

          {/* 에러 메시지 */}
          {error && <ErrorMessage>{error}</ErrorMessage>}
          
          {/* 성공 메시지 */}
          {success && <SuccessMessage>{success}</SuccessMessage>}

          {/* Google 로그인 버튼 (랜덤 사용자) */}
          <GoogleButton
            onClick={handleGoogleLogin}
            disabled={isLoading}
          >
            <svg width="20" height="20" viewBox="0 0 24 24">
              <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
              <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
              <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"/>
              <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
            </svg>
            {isLoading ? '로그인 중...' : 'Google로 로그인 (랜덤)'}
          </GoogleButton>

          {/* 구분선 */}
          <div style={{ textAlign: 'center', margin: '1rem 0', color: '#6b7280', fontSize: '0.875rem' }}>
            또는 테스트 계정으로 로그인
          </div>

          {/* 테스트 사용자 버튼들 */}
          <TestUserGrid>
            {TEST_USERS.map((user) => (
              <TestUserButton
                key={user.id}
                onClick={() => handleTestUserLogin(user)}
                disabled={isLoading}
              >
                {user.name}
              </TestUserButton>
            ))}
          </TestUserGrid>

          {/* 실패 테스트 버튼 */}
          <TestUserButton
            onClick={handleLoginError}
            disabled={isLoading}
            style={{ 
              width: '100%', 
              marginTop: '0.5rem', 
              background: '#fecaca', 
              color: '#dc2626' 
            }}
          >
            ❌ 로그인 실패 테스트
          </TestUserButton>
        </LoginCard>
      </LoginContainer>

      {/* 로딩 오버레이 */}
      {isLoading && (
        <LoadingOverlay>
          <LoadingCard>
            <LoadingSpinner />
            <div style={{ color: '#374151', fontWeight: '500' }}>
              {loadingMessage}
            </div>
          </LoadingCard>
        </LoadingOverlay>
      )}
    </>
  );
};

export default LoginPageTest;
